                throw new TopologyException("Unknown definition class: " + factory.getClass().getName());
            }
        }
    }

    return new ProcessorTopology(new ArrayList<>(processorMap.values()),
                                 topicSourceMap,
                                 topicSinkMap,
                                 new ArrayList<>(stateStoreMap.values()),
